// нХДнД∞ л≤ДнКЉ нЦЕнЛ± нФЉлУЬл∞± вАФ data-hf мЖНмД± л≤ДнКЉ нБіл¶≠ мЛЬ мІІмЭА лНФлЄФ мІДлПЩ (Android) / нБіл¶≠мЭМ (iOS)
function _hapticTap(){
  if(navigator.vibrate){ navigator.vibrate([20,40,20]); return; }
  try{
    const ctx=new (window.AudioContext||window.webkitAudioContext)();
    const osc=ctx.createOscillator(); const gain=ctx.createGain();
    osc.connect(gain); gain.connect(ctx.destination);
    osc.frequency.value=800;
    gain.gain.setValueAtTime(0.06,ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001,ctx.currentTime+0.04);
    osc.start(); osc.stop(ctx.currentTime+0.04);
  }catch(_){}
}
if(typeof document!=="undefined"){
  document.addEventListener("click",e=>{
    if(e.target.closest("[data-hf]")) _hapticTap();
  },{passive:true});
}

// мК§нЛ∞нВ§ лЛЂкЄ∞ л≤ДнКЉ мГБнШЄ л∞∞м†Ь: нХЬ нСЬлІМ мК§нЛ∞нВ§ нСЬмЛЬ
let _stickyActiveId = null;
const _stickyListeners = new Set();
const _stickyBroadcast = id => { _stickyActiveId = id; _stickyListeners.forEach(cb => cb(id)); };
function useStickyTable(myId, isVisible) {
  const { useState: _us, useEffect: _ue } = React;
  const [activeId, setActiveId] = _us(_stickyActiveId);
  _ue(() => { _stickyListeners.add(setActiveId); return () => _stickyListeners.delete(setActiveId); }, []);
  _ue(() => {
    if (isVisible) _stickyBroadcast(myId);
    else if (_stickyActiveId === myId) _stickyBroadcast(null);
  }, [isVisible, myId]);
  return activeId === myId && isVisible;
}

const toDate = raw => {
  if (!raw) return null;
  // Excel serial number (мИЂмЮРл°Ь м†АмЮ•лРЬ лВ†мІЬ, мШИ: 46162 вЖТ 2026-05-11)
  const num = Number(raw);
  if (!isNaN(num) && num > 40000 && num < 80000 && String(raw).trim().length <= 5) {
    const d = new Date(Date.UTC(1899, 11, 30) + num * 86400000);
    return d.toISOString().slice(0, 10);
  }
  // мЛЬк∞Д/AM/PM/мШ§м†Д/мШ§нЫД suffix м†Ьк±∞ вЖТ лВ†мІЬ лґАлґДлІМ мґФмґЬ нЫД нММмЛ±
  // мШИ: "5/14/26 9:47" вЖТ "5/14/26", "2026-05-14T09:47:00" вЖТ "2026-05-14"
  const s = String(raw).trim()
    .replace(/T\d{2}:\d{2}(:\d{2})?(\.\d+)?(Z|[+-]\d{2}:?\d{2})?$/, '')
    .replace(/\s+(мШ§м†Д|мШ§нЫД|AM|PM)?\s*\d{1,2}:\d{2}(:\d{2})?(\s*(AM|PM|мШ§м†Д|мШ§нЫД))?$/i, '')
    .trim();
  // YYYYлЕД MмЫФ DмЭЉ (нХЬкµ≠мЦі лВ†мІЬ нПђлІЈ)
  const mKr = s.match(/^(\d{4})лЕД\s*(\d{1,2})мЫФ\s*(\d{1,2})мЭЉ/);
  if (mKr) return `${mKr[1]}-${mKr[2].padStart(2,"0")}-${mKr[3].padStart(2,"0")}`;
  // YYYY. M. D (м†Р+к≥µл∞± нПђнХ®, мШИ: "2025. 10. 16")
  const m0 = s.match(/^(\d{4})\.\s*(\d{1,2})\.\s*(\d{1,2})/);
  if (m0) return `${m0[1]}-${m0[2].padStart(2,"0")}-${m0[3].padStart(2,"0")}`;
  const m1 = s.match(/^(\d{4})[-\/.](\d{1,2})[-\/.](\d{1,2})/);
  if (m1) return `${m1[1]}-${m1[2].padStart(2,"0")}-${m1[3].padStart(2,"0")}`;
  const m2 = s.match(/^(\d{1,2})[-\/.](\d{1,2})[-\/.](\d{4})/);
  if (m2) return `${m2[3]}-${m2[2].padStart(2,"0")}-${m2[1].padStart(2,"0")}`;
  const m3 = s.match(/^(\d{4})(\d{2})(\d{2})$/);
  if (m3) return `${m3[1]}-${m3[2]}-${m3[3]}`;
  // YYMMDD 6мЮРл¶ђ (мШИ: "241223" вЖТ 2024-12-23)
  const m4 = s.match(/^(\d{2})(\d{2})(\d{2})$/);
  if (m4) { const yr=2000+parseInt(m4[1],10); return `${yr}-${m4[2]}-${m4[3]}`; }
  // M/D/YY (Excel нПђлІЈ, мШИ: "5/14/26" вЖТ 2026-05-14)
  const m5 = s.match(/^(\d{1,2})[-\/](\d{1,2})[-\/](\d{2})$/);
  if (m5) { const yr=2000+parseInt(m5[3],10); return `${yr}-${m5[1].padStart(2,"0")}-${m5[2].padStart(2,"0")}`; }
  return null;
};

const fmtDays = days => {
  const d = Math.round(days || 0);
  if (d < 30) return `${d}мЭЉ`;
  const months = Math.round(d / 30);
  if (months < 12) return `${months}к∞ЬмЫФ`;
  const y = Math.floor(months / 12), m = months % 12;
  return m > 0 ? `${y}лЕД ${m}к∞ЬмЫФ` : `${y}лЕД`;
};

// нМРлІ§м≤Ш мЭіл¶Д м†ХкЈЬнЩФ
const normChannel = raw => {
  if (!raw) return "лѓЄлґДл•Ш";
  const v = String(raw).trim();
  if (v === "MERRYON") return "мЮРмВђл™∞";
  if (v === "мШИмХљк±∞лЮШ") return "мШ§нФДлЭЉмЭЄ мК§нЖ†мЦі";
  return v;
};

// мЭімІАмЦілУЬлѓЉ CS мїђлЯЉ вЖТ лВілґА мГБнГЬ (м†ХмГБ=л∞∞мЖ°, л∞∞мЖ°нЫД м†Дм≤і кµРнЩШ=кµРнЩШ, л∞∞мЖ°нЫД м†Дм≤і мЈ®мЖМ=л∞ШнТИ)
const normCS = raw => {
  if (!raw) return "л∞∞мЖ°";
  const v = String(raw).trim().toLowerCase().replace(/\s/g,"");
  // л∞∞мЖ° м†Д мЈ®мЖМ = 'мЈ®мЖМ' (л∞ШнТИ мХДлЛШ вАФ л∞∞мЖ° мЮРм≤ік∞А мЭЉмЦілВШмІА мХКмЭА м£ЉлђЄ лђінЪ®нЩФ)
  if (v.includes("л∞∞мЖ°м†Д") && v.includes("мЈ®мЖМ")) return "мЈ®мЖМ";
  // кЈЄ мЩЄ мЈ®мЖМ(л∞∞мЖ° нЫД/лѓЄл™ЕмЛЬ) = л∞ШнТИ м≤Шл¶ђ
  if (v.includes("мЈ®мЖМ")) return "л∞ШнТИ";
  if (v.includes("кµРнЩШ")) return "кµРнЩШ";
  return "л∞∞мЖ°";
};

// міЭ(gross) мґЬк≥† нМРм†Х вАФ мЛ§м†Ь мґЬк≥†лРЬ нЦЙ: мИЬл∞∞мЖ° + л∞∞мЖ°нЫД мЈ®мЖМ(л∞ШнТИ) + л∞∞мЖ°нЫД кµРнЩШ.
// л∞∞мЖ°м†Д мЈ®мЖМ('мЈ®мЖМ')¬ЈлѓЄл∞∞мЖ°('м£ЉлђЄ')мЭА м†ЬмЩЄ. л∞ШнТИ/кµРнЩШмЭА л≥ДлПД status л°Ь к≥ДмЖН мІСк≥ДлРШлѓАл°Ь
// 'л∞∞мЖ°'(міЭ мґЬк≥†)мЭА л∞ШнТИ¬ЈкµРнЩШмЭД лґАлґДмІСнХ©мЬЉл°Ь нПђнХ®нХЬлЛ§. (л∞ШнТИл•† лґДл™® = міЭ мґЬк≥†)
const wasShipped = s => s === "л∞∞мЖ°" || s === "л∞ШнТИ" || s === "кµРнЩШ";

// мГБнТИл™Е м†ХкЈЬнЩФ вАФ SaleCalcModal лВілґА м†ХмЭШ(normProdName)мЩА лПЩмЭЉ лПЩмЮСмЭД мЬ†мІАнХімХЉ нХЬлЛ§
// (calc_supply_override мЭШ norm_name нВ§к∞А мЦСм™љмЧРмДЬ мЭЉмєШнХімХЉ лІ§мє≠лР®). мЭЄл≤§нЖ†л¶ђ "к∞Ак≤© DB" мЧЕл°ЬлУЬмЩА
// мЭімЭµл•† к≥ДмВ∞ нЫЕ(useInventoryPricing)мЧРмДЬ мГБнТИ лІ§мє≠мЧР к≥µнЖµ мВђмЪ©.
const normProdName = s => String(s||"").trim().toLowerCase()
  .replace(/[вАЛвАМвАН пїњ]/g,"")
  .replace(/[\s_¬ЈвАҐ~\-]*\d+\s*colou?rs?\b/gi,"")
  .replace(/\[[^\]]*\]/g,"")
  .replace(/\([^)]*\)/g,"")
  .replace(/[_¬ЈвАҐ~]+/g,"")
  .replace(/\s+/g,"").trim();

// мєінОШ24 мГБнТИмљФлУЬ лІ§мє≠ м†ДмЪ© м†ХкЈЬнЩФ вАФ к≥µмЪ© normProdName к≥Љ лЛђл¶ђ мГЙмГБ [BLACK]/[BROWN] лУ±мЭА л≥ім°інХШк≥†
// л∞∞мЖ° л∞∞мІА(*мШ§лКШ мґЬл∞Ь, *MM.DD мШИмХљ л∞ЬмЖ°, *лЛємЭЉл∞ЬмЖ° вА¶)лІМ м†Ьк±∞нХЬлЛ§. лЭДмЦімУ∞кЄ∞лКФ лђімЛЬ(мЬ†мЧ∞ лІ§мє≠).
// м†АмЮ•(cafe24_product_codes.norm_name)к≥Љ SKU Risk лІ§мє≠мЧР лПЩмЭЉнХШк≤М мВђмЪ©нХі мЦСм™љ нВ§к∞А мЭЉмєШнХімХЉ нХЬлЛ§.
const normCafe24Name = s => String(s||"").split("*")[0].toLowerCase()
  .replace(/[вАЛвАМвАН пїњ]/g,"")
  .replace(/\s+/g,"").trim();
// мГЙмГБ([BLACK]/[WHITE] вА¶) м†Ьк±∞ нВ§ вАФ нХЬм™љмЧРлІМ мГЙмГБмЭі мЮИмЭД лХМл•Љ мЬДнХЬ нПіл∞± лІ§мє≠мЪ©.
const cafe24BaseKey = s => normCafe24Name(s).replace(/\[[^\]]*\]/g,"");
// мГЙмГБ нЖ†нБ∞ вЖТ лМАнСЬ hex (KRвЖФEN лПЩмЭШмЦі нЖµнХ©: WHITEвЙ°нЩФмЭінКЄ). мГЙмГБмЬЉл°Ь мЭЄмЛЭ мХИ лРШл©і null.
function colorToHex(tok){
  const t=String(tok||"").trim();
  if(!t) return null;
  return COLOR_HEX[t]||COLOR_HEX[t.toUpperCase()]||COLOR_HEX[t.toLowerCase()]||null;
}
// лђЄмЮРмЧімЧРмДЬ мГЙмГБ hex мґФмґЬ вАФ лМАкіДнШЄ [WHITE] мХИмЭілВШ мШµмЕШк∞Т(нЩФмЭінКЄ, нЩФмЭінКЄ-L лУ±)мЧРмДЬ.
function extractColorHex(...parts){
  for(const p of parts){
    const s=String(p||"");
    for(const b of (s.match(/\[([^\]]+)\]/g)||[])){ const h=colorToHex(b.slice(1,-1)); if(h) return h; }
    for(const seg of s.split(/[\s/\-_¬ЈвАҐ,]+/)){ const h=colorToHex(seg); if(h) return h; }
  }
  return null;
}

// мЭімЭµл•† мІСк≥Д лМАмГБ нМРм†Х вАФ мЈ®мЖМ/кµРнЩШ/л∞ШнТИ(нЩШлґИ) м£ЉлђЄлІМ м†ЬмЩЄнХШк≥†
// л∞∞мЖ°¬Јм£ЉлђЄ¬Јм†СмИШ¬Јл∞Ьм£Љ лУ± кЈЄ мЩЄ мГБнГЬлКФ л™®лСР нПђнХ®нХЬлЛ§.
// лВілґА status(м†ХкЈЬнЩФ) + raw_status(мЫРл≥Є CSм≤Шл¶ђ нЕНмК§нКЄ) мЦСм™љмЭД нЩХмЭЄ.
const PROFIT_EXCLUDE_STATUS = new Set(["мЈ®мЖМ","л∞ШнТИ","кµРнЩШ"]);
const isProfitCountable = r => {
  if(PROFIT_EXCLUDE_STATUS.has(r.status)) return false;
  const raw=String(r.raw_status||"").toLowerCase().replace(/\s/g,"");
  if(/мЈ®мЖМ|нЩШлґИ|л∞ШнТИ|кµРнЩШ|cancel|refund|return|exchange/.test(raw)) return false;
  return true;
};

function fmtEokMan(n){
  const eok=Math.floor(n/1e8);
  const man=Math.round((n%1e8)/1e4);
  if(man===0) return eok+"мЦµ";
  const cheon=Math.floor(man/1000);
  const baek=Math.floor((man%1000)/100);
  const sip=Math.floor((man%100)/10);
  const il=man%10;
  let s="";
  if(cheon) s+=cheon+"м≤Ь";
  if(baek) s+=baek+"л∞±";
  if(sip) s+=sip+"мЛ≠";
  if(il) s+=il;
  return eok+"мЦµ"+s+"лІМ";
}
// мЦµ мЭімГБ: м≤ЬлІМ лЛ®мЬДкєМмІАлІМ нСЬмЛЬ (нЕМмЭілЄФ мЕАмЪ©)
const fmtWonShort = n => {
  if (!n) return "вАФ";
  if (n >= 1e8) {
    const eok = Math.floor(n / 1e8);
    const cheon = Math.floor((n % 1e8) / 1e7);
    return "вВ©" + eok + "мЦµ" + (cheon > 0 ? cheon + "м≤ЬлІМ" : "");
  }
  if (n >= 1e4) return "вВ©" + Math.round(n / 1e4) + "лІМ";
  return "вВ©" + n.toLocaleString();
};
const fmtWon = n => {
  if (!n) return "вАФ";
  if (n>=1e8) return "вВ©"+fmtEokMan(n);
  if (n>=1e4) return "вВ©"+(n/1e4).toFixed(0)+"лІМ";
  return "вВ©"+n.toLocaleString();
};

