    product:      f("мГБнТИл™Е","product","нТИл™Е","item","name"),
    option:       f("мШµмЕШ","option","size","color","мВђмЭім¶И","мГЙмГБ"),
    qty:          f("мИШлЯЙ","qty","quantity","к∞ЬмИШ","нМРлІ§мИШлЯЙ","мЮЕк≥†"),
    cs:           f("cs","м≤Шл¶ђ","csм≤Шл¶ђ","csмГБнГЬ"),
    date:         f("л∞∞мЖ°мЭЉ","delivery_date")||f("м£ЉлђЄмЭЉ","лВ†мІЬ","date","order_date","м£ЉлђЄлВ†мІЬ","reg_date"),
    orderId:      f("кіАл¶ђл≤ИнШЄ","order_id","м£ЉлђЄл≤ИнШЄ","orderid"),
    memo:         f("л©Фл™®","memo","лєДк≥†","note"),
    revenue:      f("кЄИмХ°","revenue","sales","лІ§мґЬ","price","к∞Ак≤©","к≤∞м†ЬкЄИмХ°","м£ЉлђЄкЄИмХ°"),
    supply:       f("к≥µкЄЙк∞А","supply_price","мЫРк∞А","cost","лЛ®к∞А","лІ§мЮЕк∞А","к≥µкЄЙлЛ®к∞А"),
