// DATA INPUT вАФ Claude мЮРлПЩнЩФ мК§нБђл¶љнКЄ нММмЭЉнХ® (мЧЕл°ЬлУЬ / мИШм†Х / лЛ§мЪіл°ЬлУЬ)
// вФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФАвФА
const _scriptId=()=>(globalThis.crypto?.randomUUID?.()||(Date.now().toString(36)+Math.random().toString(36).slice(2)));
const _fmtBytes=n=>{const b=Number(n)||0;return b<1024?`${b} B`:b<1024*1024?`${(b/1024).toFixed(1)} KB`:`${(b/1048576).toFixed(1)} MB`;};

function ClaudeScriptPanel(){
  const KEY="claude_scripts";
  const [files,setFiles]=useState([]);
  const [msg,setMsg]=useState(null);
  const [busy,setBusy]=useState(false);
  const [editing,setEditing]=useState(null); // {id,name,content,isNew} | null
  const uploadRef=useRef(null);

  const cacheLocal=arr=>localStorage.setItem(KEY,JSON.stringify(arr));
  const sortFiles=arr=>[...arr].sort((a,b)=>String(b.updated_at||"").localeCompare(String(a.updated_at||"")));

  useEffect(()=>{
    let alive=true;
    (async()=>{
      let local=[];
      try{local=JSON.parse(localStorage.getItem(KEY)||"[]");}catch{/* ignore */}
      if(alive&&local.length) setFiles(sortFiles(local));
      try{
        const db=await getSupabase();
        const{data,error}=await db.from("claude_scripts").select("*");
        if(error||!data) return; // мШ§нФДлЭЉмЭЄ/лѓЄмЧ∞к≤∞ вЖТ л°Ьмїђ мЬ†мІА
        if(!alive) return;
        if(data.length>0){
          const rows=sortFiles(data);
          setFiles(rows);cacheLocal(rows);
        } else if(local.length>0){
          await db.from("claude_scripts").upsert(local,{onConflict:"id"}); // 1нЪМ лІИмЭікЈЄл†ИмЭімЕШ
        }
      }catch{/* л°Ьмїђ мЬ†мІА */}
    })();
    return()=>{alive=false;};
  },[]);

  const persist=async row=>{
    let saved={...row,updated_at:new Date().toISOString()};
    try{
      const db=await getSupabase();
      const{data,error}=await db.from("claude_scripts").upsert({id:row.id,name:row.name,content:row.content},{onConflict:"id"}).select().maybeSingle();
      if(error) throw error;
      if(data) saved={...saved,...data};
      setMsg({type:"success",msg:`"${saved.name}" м†АмЮ• мЩДл£М вАФ Supabase лПЩкЄ∞нЩФ.`});
    }catch{
      setMsg({type:"warn",msg:`"${saved.name}" л°ЬмїђмЧРлІМ м†АмЮ•лР® (Supabase мЧ∞к≤∞ мЛ§нМ®).`});
    }
    setFiles(prev=>{const next=sortFiles([...prev.filter(f=>f.id!==saved.id),saved]);cacheLocal(next);return next;});
    return saved;
  };

  const handleUpload=async e=>{
    const list=[...(e.target.files||[])];
    e.target.value="";
    if(!list.length) return;
    setBusy(true);
    for(const f of list){
      try{
        const text=await f.text();
        await persist({id:_scriptId(),name:f.name,content:text});
      }catch{setMsg({type:"error",msg:`"${f.name}" мЭљкЄ∞ мЛ§нМ®.`});}
    }
    setBusy(false);
  };

  const download=f=>{
    const blob=new Blob([f.content||""],{type:"text/plain;charset=utf-8"});
    const url=URL.createObjectURL(blob);
    const a=document.createElement("a");
    a.href=url;a.download=f.name||"claude-script.txt";
    document.body.appendChild(a);a.click();document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const del=async f=>{
    if(!window.confirm(`"${f.name}" нММмЭЉмЭД мВ≠м†ЬнХ†кєМмЪФ?`)) return;
    setFiles(prev=>{const next=prev.filter(x=>x.id!==f.id);cacheLocal(next);return next;});
    if(editing?.id===f.id) setEditing(null);
    try{const db=await getSupabase();await db.from("claude_scripts").delete().eq("id",f.id);}catch{/* л°Ьмїђ л∞ШмШБлР® */}
    setMsg({type:"info",msg:`"${f.name}" мВ≠м†ЬлР®.`});
  };

  const saveEdit=async()=>{
    if(!editing) return;
    if(!editing.name.trim()){setMsg({type:"error",msg:"нММмЭЉл™ЕмЭД мЮЕл†•нХШмДЄмЪФ."});return;}
    setBusy(true);
    await persist({id:editing.id,name:editing.name.trim(),content:editing.content});
    setBusy(false);
    setEditing(null);
  };

  const linkBtn={background:"transparent",border:"none",cursor:"pointer",fontSize:12,padding:"4px 6px",borderRadius:5};

  return (
    <Card>
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:12,flexWrap:"wrap"}}>
        <span style={{fontWeight:600,fontSize:13,color:D.black}}>Claude мЮРлПЩнЩФ мК§нБђл¶љнКЄ нММмЭЉнХ®</span>
        <span style={{fontSize:11,color:D.textMeta,flex:1}}>мЧЕл°ЬлУЬнХЬ нММмЭЉмЭА SupabaseмЧР м†АмЮ•лРШмЦі мЦілФФмДЬлУ† лЛ§мЪіл°ЬлУЬнХ† мИШ мЮИмКµлЛИлЛ§.</span>
        <input ref={uploadRef} type="file" multiple onChange={handleUpload} style={{display:"none"}}
          accept=".txt,.md,.py,.js,.ts,.sh,.json,.yaml,.yml,.toml,.csv,.html,.css,text/*"/>
        <Btn variant="ghost" onClick={()=>uploadRef.current?.click()} disabled={busy}>мЧЕл°ЬлУЬ</Btn>
        <Btn variant="primary" onClick={()=>setEditing({id:_scriptId(),name:"",content:"",isNew:true})}>+ мГИ нММмЭЉ</Btn>
      </div>

      {files.length===0?(
        <div style={{padding:"40px 0",textAlign:"center",color:D.textMeta,fontSize:13,
          border:`1px dashed ${D.border}`,borderRadius:8}}>
          м†АмЮ•лРЬ нММмЭЉмЭі мЧЖмКµлЛИлЛ§. нММмЭЉмЭД мЧЕл°ЬлУЬнХШк±∞лВШ мГИл°Ь лІМлУЬмДЄмЪФ.
        </div>
      ):(
        <div style={{border:`1px solid ${D.border}`,borderRadius:8,overflow:"hidden"}}>
          {files.map((f,i)=>(
            <div key={f.id} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px",
              borderTop:i?`1px solid ${D.border}`:"none",background:D.surface}}>
              <span style={{fontSize:14}}>рЯУД</span>
              <button onClick={()=>setEditing({...f,isNew:false})} title="мИШм†Х"
                style={{flex:1,minWidth:0,textAlign:"left",background:"transparent",border:"none",cursor:"pointer",
                  fontSize:13,fontWeight:500,color:D.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
                {f.name}
              </button>
              <span style={{fontSize:11,color:D.textMeta,whiteSpace:"nowrap"}}>
                {_fmtBytes(new Blob([f.content||""]).size)}
                {f.updated_at?` ¬Ј ${dayjs(f.updated_at).format("YY.MM.DD HH:mm")}`:""}
              </span>
              <button onClick={()=>download(f)} style={{...linkBtn,color:D.blue,fontWeight:600}}>лЛ§мЪіл°ЬлУЬ</button>
              <button onClick={()=>del(f)} style={{...linkBtn,color:D.red}}>мВ≠м†Ь</button>
            </div>
          ))}
        </div>
      )}

      {editing&&(
        <div style={{marginTop:14,border:`1px solid ${D.borderMid}`,borderRadius:8,padding:14,background:D.surfaceAlt}}>
          <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:10,flexWrap:"wrap"}}>
            <input value={editing.name} onChange={e=>setEditing(s=>({...s,name:e.target.value}))}
              placeholder="нММмЭЉл™Е (мШИ: automation.py)" autoFocus
              style={{flex:"1 1 240px",minWidth:200,border:`1px solid ${D.border}`,borderRadius:7,
                padding:"8px 12px",fontSize:13,color:D.text,background:D.surface,outline:"none"}}/>
            <Btn variant="primary" onClick={saveEdit} disabled={busy}>{busy?"м†АмЮ• м§СвА¶":"м†АмЮ•"}</Btn>
            <Btn variant="ghost" onClick={()=>setEditing(null)}>мЈ®мЖМ</Btn>
          </div>
          <textarea value={editing.content} onChange={e=>setEditing(s=>({...s,content:e.target.value}))} spellCheck={false}
            placeholder="мК§нБђл¶љнКЄ лВімЪ©мЭД мЮЕл†•нХШк±∞лВШ нММмЭЉмЭД мЧЕл°ЬлУЬнХШмДЄмЪФ."
            style={{width:"100%",minHeight:300,boxSizing:"border-box",resize:"vertical",
              border:`1px solid ${D.border}`,borderRadius:8,padding:"12px 14px",
              fontSize:12.5,lineHeight:1.6,color:D.text,background:D.surface,outline:"none",
              fontFamily:"'SFMono-Regular',Consolas,'Liberation Mono',Menlo,monospace",
              tabSize:2,whiteSpace:"pre"}}/>
        </div>
      )}

      <Alert type={msg?.type} msg={msg?.msg}/>
    </Card>
  );
}

function DataInput({ onUpdate, onDataChange, orders=[], stocks=[], revenues=[], storeSales=[] }) {
  const [tab,setTab]=useState("revenue");
  // мЧЕл°ЬлУЬ лВімЧ≠ нМ®лДРлУ§мЧР к∞Хм†Ь мГИл°Ьк≥†мє® мЛ†нШЄ (мВ≠м†Ь/мЧЕл°ЬлУЬ л∞ЬмГЭ мЛЬ м¶Эк∞А)
  const [histRefreshKey,setHistRefreshKey]=useState(0);
  const bumpHist=()=>setHistRefreshKey(k=>k+1);

  const lastDate=(arr,field)=>{
    const d=arr.map(r=>r[field]).filter(Boolean).sort().at(-1);
    return d?<span style={{fontSize:10,color:D.textMeta,fontWeight:400,marginLeft:4}}>({d})</span>:null;
  };

  const tabs=[
    {key:"revenue",name:"лІ§мґЬ мЮЕл†•",extra:lastDate(revenues,"date")},
    {key:"stock",name:"мЮЕк≥†",extra:lastDate(stocks,"upload_date")},
    {key:"orders",name:"м£ЉлђЄ¬Јл∞∞мЖ°",extra:lastDate(orders,"order_date")},
    {key:"store",name:"лІ§мЮ• нМРлІ§",extra:lastDate(storeSales,"sale_date")},
    {key:"inventory",name:"мЭЄл≤§нЖ†л¶ђ"},
    {key:"cs",name:"CS"},
    {key:"script",name:"мЮРлПЩнЩФ мК§нБђл¶љнКЄ"},
    {key:"delete",name:"лН∞мЭінД∞ мВ≠м†Ь"},
  ];

  const GUIDES={
    revenue:"KPI мєілУЬмЭШ лІ§мґЬ, лІ§мґЬ м†РмЬ†мЬ®, нМРлІ§м≤Шл≥Д лІ§мґЬмЭШ мЖМмК§мЮЕлЛИлЛ§.\nлІ§мґЬ кЄИмХ°мЭА мЈ®мЖМ/нЩШлґИмЭі нПђнХ®лРЬ кЄИмХ°мЭіл©∞, мЧСмЕА лЛ§мЪіл°ЬлУЬ мЛЬ к∞Б м±ДлДР мЦілУЬлѓЉмЭШ нЖµк≥ДмЧРмДЬ нЩХмЭЄнХШмДЄмЪФ.\n*лІ§мЭЉ м†ДлВ†мЭШ лН∞мЭінД∞л•Љ мЧЕл°ЬлУЬнХШмДЄмЪФ.",
    stock:"KPI мєілУЬмЭШ мЮЕк≥† мИШлЯЙ, лђЉл•Ш нФМл°ЬмЪ∞ мДємЕШ м†Дм≤імЭШ лН∞мЭінД∞ мЖМмК§мЮЕлЛИлЛ§.\n*лІ§мЭЉ м†ДлВ†мЭШ лН∞мЭінД∞л•Љ мЧЕл°ЬлУЬнХШмДЄмЪФ.",
    orders:"KPI мєілУЬмЭШ л∞∞мЖ°¬Јл∞ШнТИ мИШ, нМРлІ§м≤Ш мГБмДЄмЭШ л∞∞мЖ°¬Јл∞ШнТИ мИШ, нМРлІ§¬Јл∞ШнТИ TOP, нФМлЮЂнПЉ л≥Д мД†нШЄ¬Јл∞ШнТИ мШµмЕШ лЮ≠нВє, к∞ЭлЛ®к∞А к≥ДмВ∞мЭШ лН∞мЭінД∞ мЖМмК§мЮЕлЛИлЛ§.\nнХДмЪФ мїђлЯЉ: м£ЉлђЄл≤ИнШЄ ¬Ј м£ЉлђЄмЭЉ ¬Ј л∞∞мЖ°мЭЉ ¬Ј нМРлІ§м≤Ш ¬Ј мГБнТИл™Е ¬Ј мШµмЕШ ¬Ј мИШлЯЙ ¬Ј нМРлІ§к∞А(29CM¬ЈлђімЛ†мВђ AOV) ¬Ј к≤∞м†ЬкЄИмХ°(мЮРмВђл™∞ AOV) ¬Ј CSм≤Шл¶ђ\n*лІ§мЭЉ мµЬкЈЉ нХЬлЛђ лН∞мЭінД∞(м£ЉлђЄк±і л∞ШнТИ м†Хл≥і мЧЕлН∞мЭінКЄ)л•Љ мЧЕл°ЬлУЬнХШмДЄмЪФ.",
    store:"KPI мєілУЬмЭШ лІ§мґЬ(мШ§нФДлЭЉмЭЄ мК§нЖ†мЦі) нХ©мВ∞, лЮ≠нБђ мІАнСЬ лВі мШ§нФДлЭЉмЭЄ мК§нЖ†мЦі нХ≠л™©мЭШ лН∞мЭінД∞ мЖМмК§мЮЕлЛИлЛ§.\n*лІ§мЭЉ мµЬкЈЉ нХЬлЛђмЭШ лН∞мЭінД∞л•Љ мЧЕл°ЬлУЬнХШмДЄмЪФ.",
    inventory:"лН∞мЭінД∞ мїінОШмЦі(SKU Risk ¬Ј Aging Trend)мЩА л¶ђмШ§лНФ к≥ДмВ∞кЄ∞мЭШ к≥µнЖµ лН∞мЭінД∞ мЖМмК§мЮЕлЛИлЛ§.\nмЧСмЕАмЧР к∞АмЪ©мЮђк≥† ¬Ј мЮЕк≥†лМАкЄ∞ ¬Ј 1м£Љл∞Ьм£ЉнХ©к≥Д ¬Ј 4м£Љл∞Ьм£ЉнХ©к≥Д мїђлЯЉмЭі мЮИмЬЉл©і л¶ђмШ§лНФ лН∞мЭінД∞к∞А мЮРлПЩ к≥ДмВ∞лР©лЛИлЛ§.",
    cs:"л∞ШнТИ лЮ≠нБђ мГБнТИмЭШ м£ЉмЪФ л∞ШнТИ мВђмЬ† лН∞мЭінД∞ мЖМмК§л°Ь лІ§мє≠лР©лЛИлЛ§.\n*лІ§мЭЉ м†ДлВ† лН∞мЭінД∞л•Љ мЧЕл°ЬлУЬнХШмДЄмЪФ.",
  };
  const DC_LIGHT={bg:"#f8f8f6",card:"#ffffff",border:"#e0e0da",text:"#111111",sub:"#444444",dim:"#888888"};

  return (
    <div style={{padding:"20px 24px",maxWidth:1400,margin:"0 auto"}}>
      {/* нГ≠ л∞Ф вАФ мДємЕШл™ЕмЧР нЕМлСРл¶ђ л∞ХмК§ */}
      <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:20}}>
        {tabs.map(t=>(
          <button key={t.key} onClick={()=>setTab(t.key)}
            style={{background:tab===t.key?D.black:"transparent",
              color:tab===t.key?"#fff":D.textSub,
              border:`1.5px solid ${tab===t.key?D.black:D.borderMid}`,
              borderRadius:6,padding:"6px 14px",fontWeight:tab===t.key?700:400,
              fontSize:12,cursor:"pointer",transition:"all 0.12s",
              display:"flex",alignItems:"center",gap:4}}>
            {t.name}{t.extra}
          </button>
        ))}
      </div>

      {/* к∞АмЭілУЬ мДємЕШ (мВ≠м†Ь нГ≠ м†ЬмЩЄ) */}
      {tab!=="delete"&&GUIDES[tab]&&(
        <GuideSection tabKey={tab} desc={GUIDES[tab]} isDark={false}/>
      )}

      {tab==="revenue"&&<RevenueForm onUpdate={ts=>onUpdate("revenue",ts)} histRefreshKey={histRefreshKey}/>}
      {tab==="stock"&&<StockUploader onUpdate={ts=>onUpdate("stock",ts)} histRefreshKey={histRefreshKey}/>}
      {tab==="orders"&&<EasyAdminUploader onUpdate={ts=>{onUpdate("orders",ts);onDataChange?.();bumpHist();}} histRefreshKey={histRefreshKey}/>}
      {tab==="store"&&<StoreUploader onUpdate={ts=>{onUpdate("store",ts);onDataChange?.();bumpHist();}} histRefreshKey={histRefreshKey}/>}
      {tab==="inventory"&&(
        <div style={{background:DC_LIGHT.card,border:`1px solid ${DC_LIGHT.border}`,borderRadius:12,padding:"20px 20px 24px"}}>
          <div style={{fontWeight:600,fontSize:16,color:DC_LIGHT.text,letterSpacing:"-0.2px",marginBottom:16}}>Inventory мЧЕл°ЬлНФ</div>
          <InventoryUploader DC={DC_LIGHT} onUploaded={()=>onDataChange?.()} onReorderDone={()=>onDataChange?.()}/>
        </div>
      )}
      {tab==="cs"&&<CSDataInput/>}
      {tab==="script"&&<ClaudeScriptPanel/>}
      {tab==="delete"&&(
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:14}}>
          <DataDeleteSection table="revenues" dateField="date" label="лІ§мґЬ мЮЕл†•" onDone={()=>{onDataChange?.();bumpHist();}}/>
          <DataDeleteSection table="stock_uploads" dateField="upload_date" label="мЮЕк≥†" onDone={()=>{onDataChange?.();bumpHist();}}/>
          <DataDeleteSection table="order_headers" dateField="order_date" label="м£ЉлђЄ¬Јл∞∞мЖ°" onDone={()=>{onDataChange?.();bumpHist();}}/>
          <DataDeleteSection table="store_sales" dateField="sale_date" label="лІ§мЮ• нМРлІ§" onDone={()=>{onDataChange?.();bumpHist();}}/>
        </div>
      )}
    </div>
  );
}

